345	export function setError(state: AppState, threadId: ThreadId, error: string | null): AppState {
346	  const threads = updateThread(state.threads, threadId, (t) => {
347	    if (t.error === error) return t;
348	    return { ...t, error };
349	  });
350	  return threads === state.threads ? state : { ...state, threads };
351	}
