324	export function toggleProject(state: AppState, projectId: Project["id"]): AppState {
325	  return {
326	    ...state,
327	    projects: state.projects.map((p) => (p.id === projectId ? { ...p, expanded: !p.expanded } : p)),
328	  };
329	}
