374	interface AppStore extends AppState {
375	  syncServerReadModel: (readModel: OrchestrationReadModel) => void;
376	  markThreadVisited: (threadId: ThreadId, visitedAt?: string) => void;
377	  markThreadUnread: (threadId: ThreadId) => void;
378	  toggleProject: (projectId: Project["id"]) => void;
379	  setProjectExpanded: (projectId: Project["id"], expanded: boolean) => void;
380	  setError: (threadId: ThreadId, error: string | null) => void;
381	  setThreadBranch: (threadId: ThreadId, branch: string | null, worktreePath: string | null) => void;
382	}
383	
384	export const useStore = create<AppStore>((set) => ({
385	  ...readPersistedState(),
386	  syncServerReadModel: (readModel) => set((state) => syncServerReadModel(state, readModel)),
387	  markThreadVisited: (threadId, visitedAt) =>
388	    set((state) => markThreadVisited(state, threadId, visitedAt)),
389	  markThreadUnread: (threadId) => set((state) => markThreadUnread(state, threadId)),
390	  toggleProject: (projectId) => set((state) => toggleProject(state, projectId)),
391	  setProjectExpanded: (projectId, expanded) =>
392	    set((state) => setProjectExpanded(state, projectId, expanded)),
393	  setError: (threadId, error) => set((state) => setError(state, threadId, error)),
394	  setThreadBranch: (threadId, branch, worktreePath) =>
395	    set((state) => setThreadBranch(state, threadId, branch, worktreePath)),
396	}));
397	
398	// Persist on every state change
399	useStore.subscribe((state) => persistState(state));
400	
401	export function StoreProvider({ children }: { children: ReactNode }) {
402	  useEffect(() => {
403	    persistState(useStore.getState());
404	  }, []);
405	  return createElement(Fragment, null, children);
406	}
