  "import": "./src/themes.ts"
}
```

---

## Step 4: `apps/web/src/hooks/useTheme.ts` (modify)

**Replace** the existing 106-line hook with an extended version that manages theme selection.

### Storage

- **Key**: `"t3code:theme"` (reuse existing key)
- **Value**: a theme ID string (`"t3-dark"`, `"t3-light"`, `"t3-midnight"`) — default `"t3-dark"`

This replaces the old `"light" | "dark" | "system"` value. On first load, if the stored value doesn't match a known theme ID, fall back to `"t3-dark"`.

### Module-level initialization (prevent flash)

```typescript
import { getTheme, listThemes, themeToCssProperties, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  return (raw && getTheme(raw)) ? raw : DEFAULT_THEME_ID;
}

function applyThemeToDOM(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class based on colorScheme
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");

  // Apply all CSS custom properties
  const props = themeToCssProperties(theme);
  for (const [key, value] of Object.entries(props)) {
    document.documentElement.style.setProperty(key, value);
  }

  if (suppressTransitions) {
    document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load
applyThemeToDOM(getTheme(getStoredThemeId())!);
```

### `useSyncExternalStore` pattern (preserved)

Keep the existing pattern: module-level `listeners` array, `emitChange()`, `subscribe()` with `matchMedia` and `storage` event listeners, `getSnapshot()` with referential stability.

### Hook return value

```typescript
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const theme: Theme = snapshot.theme;
  const resolvedTheme = theme.colorScheme;

  const setTheme = useCallback((themeId: string) => {
    const next = getTheme(themeId);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, themeId);
    applyThemeToDOM(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  return { theme, setTheme, resolvedTheme, availableThemes } as const;
}
```

