/**
 * Theme definitions and lookup utilities.
 *
 * All color values are self-contained CSS color literals (oklch, hex, rgb/rgba)
 * so they work both as inline style values and as swatch previews without
 * requiring a Tailwind context.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  /** Whether Tailwind's `.dark` variant should be active. */
  readonly colorScheme: "light" | "dark";
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

// ---------------------------------------------------------------------------
// CSS variable mapping
// ---------------------------------------------------------------------------

/**
 * Complete set of CSS custom property names consumed by the app's Tailwind
 * theme layer (see `apps/web/src/index.css`).
 */
const CSS_VAR_KEYS = [
  "background",
  "foreground",
  "card",
  "card-foreground",
  "popover",
  "popover-foreground",
  "primary",
  "primary-foreground",
  "secondary",
  "secondary-foreground",
  "muted",
  "muted-foreground",
  "accent",
  "accent-foreground",
  "destructive",
  "destructive-foreground",
  "border",
  "input",
  "ring",
  "info",
  "info-foreground",
  "success",
  "success-foreground",
  "warning",
  "warning-foreground",
  "sidebar",
  "editor",
  "terminal",
  "status-bar",
] as const;

export type CssVarKey = (typeof CSS_VAR_KEYS)[number];

/** All CSS custom property names the theme system manages. */
export function getCssVarKeys(): readonly string[] {
  return CSS_VAR_KEYS;
}

/**
 * Expand a `Theme` into a flat `Record<"--<name>", value>` suitable for
 * setting on `document.documentElement.style`.
 *
 * The seven `ThemeColors` slots are mapped to the full set of ~25 CSS custom
 * properties that the Tailwind layer expects. Derived values (card, muted,
 * border, etc.) are computed from the base colors using `color-mix()` so they
 * harmonize automatically.
 */
export function themeToCssProperties(theme: Theme): Record<string, string> {
  const { colors, colorScheme } = theme;
  const isDark = colorScheme === "dark";

  // Helpers to derive lighter/darker shades via color-mix
  const mix = (a: string, b: string, pct: number) =>
    `color-mix(in srgb, ${a} ${pct}%, ${b})`;

  const bg = colors.background;
  const fg = colors.foreground;
  const accent = colors.accent;

  const card = isDark ? mix(bg, "#ffffff", 98) : bg;
  const popover = card;
  const muted = isDark ? `rgba(255,255,255,0.04)` : `rgba(0,0,0,0.04)`;
  const mutedFg = isDark ? mix(fg, bg, 55) : mix(fg, bg, 55);
  const secondary = muted;
  const border = isDark ? `rgba(255,255,255,0.06)` : `rgba(0,0,0,0.08)`;
  const input = isDark ? `rgba(255,255,255,0.08)` : `rgba(0,0,0,0.10)`;

  const props: Record<string, string> = {
    "--background": bg,
    "--foreground": fg,
    "--card": card,
    "--card-foreground": fg,
    "--popover": popover,
    "--popover-foreground": fg,
    "--primary": accent,
    "--primary-foreground": isDark ? "#ffffff" : "#ffffff",
    "--secondary": secondary,
    "--secondary-foreground": fg,
    "--muted": muted,
    "--muted-foreground": mutedFg,
    "--accent": muted,
    "--accent-foreground": fg,
    "--destructive": isDark
      ? "color-mix(in srgb, #ef4444 90%, #ffffff)"
      : "#ef4444",
    "--destructive-foreground": isDark ? "#f87171" : "#b91c1c",
    "--border": border,
    "--input": input,
    "--ring": accent,
    "--info": "#3b82f6",
    "--info-foreground": isDark ? "#60a5fa" : "#1d4ed8",
    "--success": "#10b981",
    "--success-foreground": isDark ? "#34d399" : "#047857",
    "--warning": "#f59e0b",
    "--warning-foreground": isDark ? "#fbbf24" : "#b45309",
    "--sidebar": colors.sidebar,
    "--editor": colors.editor,
    "--terminal": colors.terminal,
    "--status-bar": colors.statusBar,
  };

  return props;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const DEFAULT_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colorScheme: "dark",
    colors: {
      background: "oklch(0.145 0.005 286)",
      foreground: "oklch(0.93 0.005 286)",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "oklch(0.13 0.005 286)",
      editor: "oklch(0.145 0.005 286)",
      terminal: "oklch(0.115 0.005 286)",
      statusBar: "oklch(0.175 0.005 286)",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colorScheme: "light",
    colors: {
      background: "#ffffff",
      foreground: "oklch(0.269 0.006 286)",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "oklch(0.97 0.002 286)",
      editor: "#ffffff",
      terminal: "oklch(0.97 0.002 286)",
      statusBar: "oklch(0.95 0.003 286)",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colorScheme: "dark",
    colors: {
      background: "oklch(0.16 0.03 270)",
      foreground: "oklch(0.92 0.01 270)",
      accent: "oklch(0.65 0.25 275)",
      sidebar: "oklch(0.13 0.035 270)",
      editor: "oklch(0.16 0.03 270)",
      terminal: "oklch(0.11 0.035 270)",
      statusBar: "oklch(0.20 0.025 270)",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: 14,
  },
];

// ---------------------------------------------------------------------------
// Lookup functions
// ---------------------------------------------------------------------------

/** Return the theme with the given `id`, or `undefined` if not found. */
export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

/** Return the full list of built-in themes. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

