import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getCssVarKeys,
  getTheme,
  listThemes,
  themeToCssProperties,
  type Theme,
} from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";

// ---------------------------------------------------------------------------
// Module-level external-store state
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

type ThemeSnapshot = {
  themeId: string;
};

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------------------------------------------------------------------------
// Storage helpers
// ---------------------------------------------------------------------------

function getStoredThemeId(): string {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw && getTheme(raw)) return raw;
  } catch {
    // localStorage may throw in restricted contexts
  }
  return DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

/** All CSS variable names the theme system may write as inline styles. */
const ALL_CSS_VAR_NAMES: readonly string[] = getCssVarKeys().map((k) => `--${k}`);

/**
 * Apply a resolved `Theme` to the document root.
 *
 * Sets CSS custom properties as inline styles (highest specificity) so they
 * override both the `:root` and `@variant dark` blocks in index.css.
 *
 * Also toggles the `.dark` class so Tailwind's dark variant remains correct.
 */
function applyThemeToDOM(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle Tailwind dark variant
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");

  // Clear any stale inline properties, then apply the new set
  const style = document.documentElement.style;
  for (const name of ALL_CSS_VAR_NAMES) {
    style.removeProperty(name);
  }

  const props = themeToCssProperties(theme);
  for (const [name, value] of Object.entries(props)) {
    style.setProperty(name, value);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Initialise immediately (prevent flash of wrong theme on load)
// ---------------------------------------------------------------------------

applyThemeToDOM(getTheme(getStoredThemeId())!);

// ---------------------------------------------------------------------------
// External store implementation for useSyncExternalStore
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const themeId = getStoredThemeId();

  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const resolved = getTheme(getStoredThemeId());
      if (resolved) applyThemeToDOM(resolved, true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const theme: Theme = getTheme(snapshot.themeId) ?? getTheme(DEFAULT_THEME_ID)!;
  const resolvedTheme: "light" | "dark" = theme.colorScheme;
  const availableThemes = listThemes();

  const setTheme = useCallback((themeId: string) => {
    const next = getTheme(themeId);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, themeId);
    applyThemeToDOM(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyThemeToDOM(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, availableThemes } as const;
}

