import type { ThemeColors } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch preview
// ---------------------------------------------------------------------------

const SWATCH_KEYS: readonly (keyof ThemeColors)[] = [
  "background",
  "sidebar",
  "editor",
  "accent",
  "foreground",
];

function ThemeSwatches({ colors }: { colors: ThemeColors }) {
  return (
    <span className="flex gap-1.5">
      {SWATCH_KEYS.map((key) => (
        <span
          key={key}
          className="size-4 rounded-full border border-border/60"
          style={{ backgroundColor: colors[key] }}
          aria-hidden="true"
        />
      ))}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Theme selector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <span className="flex flex-col gap-1">
              <span className="text-sm font-medium">{t.name}</span>
              <ThemeSwatches colors={t.colors} />
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

