import { describe, expect, it } from "vitest";

import { getCssVarKeys, getTheme, listThemes, themeToCssProperties } from "./themes";

describe("themes", () => {
  describe("listThemes", () => {
    it("returns at least 3 built-in themes", () => {
      const themes = listThemes();
      expect(themes.length).toBeGreaterThanOrEqual(3);
    });

    it("every theme has a unique id", () => {
      const ids = listThemes().map((t) => t.id);
      expect(new Set(ids).size).toBe(ids.length);
    });

    it("every theme has a non-empty name", () => {
      for (const theme of listThemes()) {
        expect(theme.name.length).toBeGreaterThan(0);
      }
    });

    it("every theme has a valid colorScheme", () => {
      for (const theme of listThemes()) {
        expect(["light", "dark"]).toContain(theme.colorScheme);
      }
    });

    it("every theme colors object has all required keys", () => {
      const requiredKeys = [
        "background",
        "foreground",
        "accent",
        "sidebar",
        "editor",
        "terminal",
        "statusBar",
      ];
      for (const theme of listThemes()) {
        for (const key of requiredKeys) {
          expect(theme.colors).toHaveProperty(key);
          expect((theme.colors as Record<string, string>)[key].length).toBeGreaterThan(0);
        }
      }
    });
  });

  describe("getTheme", () => {
    it("returns the t3-dark theme", () => {
      const theme = getTheme("t3-dark");
      expect(theme).toBeDefined();
      expect(theme!.id).toBe("t3-dark");
      expect(theme!.colorScheme).toBe("dark");
    });

    it("returns the t3-light theme", () => {
      const theme = getTheme("t3-light");
      expect(theme).toBeDefined();
      expect(theme!.id).toBe("t3-light");
      expect(theme!.colorScheme).toBe("light");
    });

    it("returns the t3-midnight theme", () => {
      const theme = getTheme("t3-midnight");
      expect(theme).toBeDefined();
      expect(theme!.id).toBe("t3-midnight");
      expect(theme!.colorScheme).toBe("dark");
    });

    it("returns undefined for unknown ids", () => {
      expect(getTheme("nonexistent")).toBeUndefined();
      expect(getTheme("")).toBeUndefined();
    });
  });

  describe("themeToCssProperties", () => {
    it("returns an object with --background and --foreground keys", () => {
      const theme = getTheme("t3-dark")!;
      const props = themeToCssProperties(theme);
      expect(props).toHaveProperty("--background");
      expect(props).toHaveProperty("--foreground");
    });

    it("maps accent to --primary and --ring", () => {
      const theme = getTheme("t3-dark")!;
      const props = themeToCssProperties(theme);
      expect(props["--primary"]).toBe(theme.colors.accent);
      expect(props["--ring"]).toBe(theme.colors.accent);
    });

    it("includes all core app CSS variable keys", () => {
      const theme = getTheme("t3-light")!;
      const props = themeToCssProperties(theme);
      const coreKeys = [
        "--background",
        "--foreground",
        "--card",
        "--card-foreground",
        "--popover",
        "--popover-foreground",
        "--primary",
        "--primary-foreground",
        "--secondary",
        "--secondary-foreground",
        "--muted",
        "--muted-foreground",
        "--accent",
        "--accent-foreground",
        "--destructive",
        "--destructive-foreground",
        "--border",
        "--input",
        "--ring",
        "--info",
        "--info-foreground",
        "--success",
        "--success-foreground",
        "--warning",
        "--warning-foreground",
        "--sidebar",
        "--editor",
        "--terminal",
        "--status-bar",
      ];
      for (const key of coreKeys) {
        expect(props).toHaveProperty(key);
        expect(props[key].length).toBeGreaterThan(0);
      }
    });

    it("produces different border values for light vs dark themes", () => {
      const lightProps = themeToCssProperties(getTheme("t3-light")!);
      const darkProps = themeToCssProperties(getTheme("t3-dark")!);
      expect(lightProps["--border"]).not.toBe(darkProps["--border"]);
    });
  });

  describe("getCssVarKeys", () => {
    it("returns a non-empty array of variable name strings", () => {
      const keys = getCssVarKeys();
      expect(keys.length).toBeGreaterThan(0);
      for (const key of keys) {
        expect(typeof key).toBe("string");
        expect(key.length).toBeGreaterThan(0);
      }
    });
  });
});

